  ('dietitian-moex-00003', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '對於全素食民眾，素食飲食指標建議每日可攝取下列何種食物以獲得維生素D？', '["穀類", "豆類", "菇類", "水果類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00004', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '國人膳食營養素參考攝取量（Dietary Reference Intakes, DRIs）對健康成人的維生素C的上限攝 取量（Tolerable Upper Intake Levels, UL）是每日多少毫克？', '["1,000", "2,000", "3,000", "4,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00005', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '世界衛生組織建議，游離糖（free sugar）攝取量最多不超過多少總熱量百分比？', '["5%", "8%", "10%", "12%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00006', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列關於我國「兒童生長曲線百分位圖」，何者錯誤？', '["0～5歲的曲線圖是根據我國兒童生長狀況所繪製", "0～5歲的曲線圖資料是來自以母乳哺育並適時添加副食品、有良好衛生照護的嬰兒或兒童", "0～5歲的曲線圖資料是來自於不吸菸母親的嬰兒或兒童", "當嬰兒的生長曲線超過第97百分位或是低於第3百分位，應請醫師檢查其健康狀況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00007', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '臺灣國民營養監測、調查、營養教育、健康飲食宣導及膳食營養素建議攝取量標準之擬定，主要是 由那個機關負責統籌規劃？', '["衛生福利部國民健康署", "衛生福利部食品藥物管理署", "教育部國民及學前教育署", "臺灣營養學會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00008', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關「社區營養推廣中心」，下列敘述何者錯誤？', '["民國107年起國民健康署倡議22縣市政府衛生局成立在地「社區營養推廣中心」", "社區營養推廣中心擔負社區民眾「恁的營養阮來顧」的重要任務", "社區營養推廣中心的標識（logo）圖樣意涵為「6大類食物」結合「幸福笑臉」", "社區營養推廣中心提供的服務包括「在地居民營養問題分析」、「社區營養照護人員培訓」、「社 區營養教育」、「營養風險篩檢」、「提供健康餐飲」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00009', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於智慧化校園餐飲服務平臺（智餐平臺），下列敘述何者錯誤？', '["「智餐平臺」於民國108年度開始規劃與建置，以科技化管理取代人工行政工作，希望減輕午餐業 務的行政負荷", "「智餐平臺」和「校園食材登錄平臺」，是兩個截然不同的系統，資訊無法互相連結", "「智餐平臺」系統建置的目的是將須運算的工作資訊化，達到省時、省力、省資源的效益，並可降 低出錯的機率", "「智餐平臺」系統中有提供「APP辨識免人工輸入」功能，可以簡化驗收及登錄流程"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00010', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關兒童營養教學資源，目前政府與民間網路資源豐富，下列那一個網站較無法提供相關資源？', '["衛福部健康99網站", "董氏基金會網站", "大享食育協會網站", "教育部國民及學前教育署網站"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-00011', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '衛生福利部長期照顧十年計畫2.0所提供長者「餐食照顧」組合中，不給付下列那個項目？', '["購買食材", "製備餐點", "用餐後的善後工作", "製備管灌飲食"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
